def solve(base: dict, patch: dict) -> dict:
    result = {}
    for key in base:
        if key not in patch:
            result[key] = base[key]
    for key, value in patch.items():
        if value is None:
            result.pop(key, None)
        else:
            base_value = base.get(key)
            if isinstance(value, dict) and isinstance(base_value, dict):
                result[key] = solve(base_value, value)
            else:
                result[key] = value
    return result
