def solve(s: str) -> bool:
    stack = []
    in_single = False
    in_double = False
    i = 0
    n = len(s)
    while i < n:
        ch = s[i]
        if in_single:
            if ch == '\\':
                i += 2
                continue
            elif ch == "'":
                in_single = False
            i += 1
        elif in_double:
            if ch == '\\':
                i += 2
                continue
            elif ch == '"':
                in_double = False
            i += 1
        else:
            if ch == "'":
                in_single = True
            elif ch == '"':
                in_double = True
            elif ch == '(' or ch == '[' or ch == '{':
                stack.append(ch)
            elif ch == ')':
                if not stack or stack[-1] != '(':
                    return False
                stack.pop()
            elif ch == ']':
                if not stack or stack[-1] != '[':
                    return False
                stack.pop()
            elif ch == '}':
                if not stack or stack[-1] != '{':
                    return False
                stack.pop()
            i += 1
    return not stack and not in_single and not in_double
