def solve(nums: list[int]) -> int:
    n = len(nums)
    if n == 1:
        return nums[0]
    left = [0] * n
    left[0] = nums[0]
    for i in range(1, n):
        left[i] = max(nums[i], left[i-1] + nums[i])
    right = [0] * n
    right[-1] = nums[-1]
    for i in range(n-2, -1, -1):
        right[i] = max(nums[i], right[i+1] + nums[i])
    ans = float('-inf')
    for i in range(n):
        if i == 0:
            cur = right[1]
        elif i == n - 1:
            cur = left[n-2]
        else:
            cur = max(left[i-1], right[i+1], left[i-1] + right[i+1])
        ans = max(ans, cur)
    return ans
